class Solution:
    def removeCoveredIntervals(self, intervals) -> int:
        n = len(intervals)
        count = 0
        for i in range(n):
            li, ri = intervals[i]
            covered = False
            for j in range(n):
                if i == j:
                    continue
                lj, rj = intervals[j]
                if lj <= li and ri <= rj:
                    if (lj, rj) == (li, ri) and j > i:
                        continue
                    covered = True
                    break
            if not covered:
                count += 1
        return count

